package com.games.riddleTemplete;public class PromptTemplates {    public static String generateRiddlePrompt(String difficulty, String category) {        return String.format("""                Generate exactly ONE riddle.                                Constraints:                - Difficulty: %s                - Category: %s                   - Must be safe for all ages                - Make it clever and non-obvious                - Do NOT reuse common riddles                STRICT OUTPUT RULES:                - Respond ONLY in valid JSON                - Do NOT include explanations or extra text                - Ensure JSON is parseable                FIELD RULES:                - "question": clear and engaging riddle                - "answer": ONLY one word (no spaces, lowercase)                - "hint": 1 to 3 words maximum, subtle clue                Output format:                {                "question": "...",                "answer": "...",                "hint": "..."                }                """, difficulty, category);    }    public static String evaluateAnswerPrompt(String riddleQuestion, String correctAnswer, String userAnswer) {        return String.format("""                A player answered a riddle. Evaluate their response:                                Riddle: %s                Correct Answer: %s                Player's Answer: %s                                Determine if the player's answer is correct or close enough to be accepted.                Then provide:                1. A brief, encouraging or consoling feedback message (1-2 sentences)                2. A short explanation of the answer                                Respond ONLY in the following JSON format:                {                  "accepted": true or false,                  "feedback": "Encouraging/consoling message here",                  "explanation": "Brief explanation of the answer"                }                """, riddleQuestion, correctAnswer, userAnswer);    }    public static String generateHintPrompt(String riddleQuestion, String answer) {        return String.format("""                For the following riddle, generate a subtle hint that helps the player without giving away the answer directly.                                Riddle: %s                Answer: %s                                Respond with ONLY the hint text, nothing else.                """, riddleQuestion, answer);    }    public static String generateCategoryRiddlePrompt(String category) {        return String.format("""                Generate a creative riddle about the topic: %s                                Requirements:                - Be witty and engaging                - Suitable for all ages                - Medium difficulty                                Respond ONLY in this JSON format:                {                  "question": "The riddle question",                  "answer": "The answer",                  "hint": "A subtle hint"                }                """, category);    }}